#!/bin/bash  # P-BOX Linux One-Click Installation Script # https://github.com/xiaomaye/P-BOX  set -e  # Colors RED='\033[0;31m' GREEN='\033[0;32m' YELLOW='\033[1;33m' BLUE='\033[0;34m' CYAN='\033[0;36m' NC='\033[0m'  # Configuration INSTALL_DIR="/etc/p-box" SERVICE_NAME="p-box" DEFAULT_PORT=8666 FIXED_VERSION="3.1.6"  # 固定版本号  echo -e "${CYAN}" echo "╔════════════════════════════════════════╗" echo "║     🚀 P-BOX Linux Installer           ║" echo "╚════════════════════════════════════════╝" echo -e "${NC}"  # Check root if [ "$EUID" -ne 0 ]; then     echo -e "`latex-inlineEquation {RED}❌ Please run as root (sudo)`{NC}"     exit 1 fi  # Detect architecture detect_arch() {     local arch=$(uname -m)     case "$arch" in         x86_64|amd64)             echo "amd64"             ;;         aarch64|arm64)             echo "arm64"             ;;         *)             echo ""             ;;     esac }  ARCH=$(detect_arch) if [ -z "$ARCH" ]; then     echo -e "`latex-inlineEquation {RED}❌ Unsupported architecture: `(uname -m)${NC}"     exit 1 fi echo -e "`latex-inlineEquation {GREEN}✓ Detected architecture: `{CYAN}`latex-inlineEquation {ARCH}`{NC}"  # 固定版本号 VERSION="$FIXED_VERSION" echo -e "`latex-inlineEquation {GREEN}✓ Using fixed version: `{CYAN}v`latex-inlineEquation {VERSION}`{NC}"  # 直接构造下载URL FILENAME="p-box-`latex-inlineEquation {VERSION}-linux-`{ARCH}.tar.gz" DOWNLOAD_URL="https://github.com/xiaomaye/P-BOX/releases/download/`latex-inlineEquation {VERSION}/`{FILENAME}"  echo -e "`latex-inlineEquation {BLUE}📥 Downloading P-BOX from GitHub...`{NC}"  TEMP_DIR=$(mktemp -d) TEMP_FILE="`latex-inlineEquation {TEMP_DIR}/`{FILENAME}"  # Download with retry logic download_success=false for i in {1..3}; do     if command -v curl &> /dev/null; then         if curl -sL -o "`latex-inlineEquation TEMP_FILE" "`DOWNLOAD_URL"; then             download_success=true             break         fi     elif command -v wget &> /dev/null; then         if wget -q -O "`latex-inlineEquation TEMP_FILE" "`DOWNLOAD_URL"; then             download_success=true             break         fi     fi     echo -e "`latex-inlineEquation {YELLOW}⚠️ Download attempt `{i} failed, retrying...${NC}"     sleep 2 done  if [ "$download_success" = false ]; then     echo -e "`latex-inlineEquation {RED}❌ Download failed after 3 attempts`{NC}"     rm -rf "$TEMP_DIR"     exit 1 fi  # Verify downloaded file if [ ! -s "`latex-inlineEquation TEMP_FILE" ] || ! file "`TEMP_FILE" | grep -q "gzip"; then     echo -e "`latex-inlineEquation {RED}❌ Downloaded file is invalid or corrupted`{NC}"     rm -rf "$TEMP_DIR"     exit 1 fi  echo -e "`latex-inlineEquation {GREEN}✓ Downloaded successfully from GitHub`{NC}"  # ... 后续安装代码保持不变（停止服务、解压、安装等）... # 注意：保持原脚本中从"Stop existing service"开始到最后的代码不变
